// HasAccount applies the HasEdge predicate on the "account" edge.
func HasAccount() predicate.LedgerSubAccountRoute {
	return predicate.LedgerSubAccountRoute(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, AccountTable, AccountColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasAccountWith applies the HasEdge predicate on the "account" edge with a given conditions (other predicates).
func HasAccountWith(preds ...predicate.LedgerAccount) predicate.LedgerSubAccountRoute {
	return predicate.LedgerSubAccountRoute(func(s *sql.Selector) {
		step := newAccountStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasSubAccounts applies the HasEdge predicate on the "sub_accounts" edge.
func HasSubAccounts() predicate.LedgerSubAccountRoute {
	return predicate.LedgerSubAccountRoute(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, SubAccountsTable, SubAccountsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasSubAccountsWith applies the HasEdge predicate on the "sub_accounts" edge with a given conditions (other predicates).
func HasSubAccountsWith(preds ...predicate.LedgerSubAccount) predicate.LedgerSubAccountRoute {
	return predicate.LedgerSubAccountRoute(func(s *sql.Selector) {
		step := newSubAccountsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.LedgerSubAccountRoute) predicate.LedgerSubAccountRoute {
	return predicate.LedgerSubAccountRoute(sql.AndPredicates(predicates...))
}

